def optimal_hash_size(nums, lo, hi):
    best_m = lo
    best_score = float('inf')

    for m in range(lo, hi + 1):
        buckets = {}
        for x in nums:
            b = x % m
            buckets[b] = buckets.get(b, 0) + 1

        score = sum(k * (k - 1) // 2 for k in buckets.values())

        if score < best_score:
            best_score = score
            best_m = m

    return (best_m, best_score)

