import unittest

class TestSolution(unittest.TestCase):

    def test_basic_no_collisions(self):
        # m=5 gives all distinct buckets
        self.assertEqual(optimal_hash_size([1, 2, 3, 4, 5], 2, 5), (5, 0))

    def test_all_same_elements(self):
        # Any m gives C(3,2)=3 collisions, smallest m wins
        self.assertEqual(optimal_hash_size([7, 7, 7], 3, 5), (3, 3))

    def test_multiples_of_six(self):
        # Multiples of 6: primes distribute better
        self.assertEqual(optimal_hash_size([6, 12, 18, 24], 3, 8), (5, 0))

    def test_hidden_number_theory_gcd(self):
        # Two arithmetic progressions with step 6
        # m=6 clusters badly (gcd=6), m=5 and m=7 spread well
        self.assertEqual(optimal_hash_size([0, 6, 12, 18, 1, 7, 13, 19], 5, 7), (5, 3))

    def test_hidden_single_element(self):
        # Single element: always 0 collisions, smallest m wins
        self.assertEqual(optimal_hash_size([42], 1, 10), (1, 0))

    def test_hidden_single_m(self):
        # Only one choice for m
        self.assertEqual(optimal_hash_size([1, 2, 3], 2, 2), (2, 1))

    def test_hidden_all_same_five(self):
        # 5 identical elements, always C(5,2)=10 regardless of m
        self.assertEqual(optimal_hash_size([7, 7, 7, 7, 7], 1, 5), (1, 10))

    def test_hidden_large_even_numbers(self):
        # 50 even numbers [0,2,...,98], m in [10,15]
        # m=15: gcd(2,15)=1, all 15 buckets, score=60
        nums = list(range(0, 100, 2))
        self.assertEqual(optimal_hash_size(nums, 10, 15), (15, 60))

    def test_hidden_primes_vs_composites(self):
        # Multiples of 6: m=11 (prime) distributes perfectly
        nums = [6 * i for i in range(1, 21)]
        self.assertEqual(optimal_hash_size(nums, 5, 12), (11, 9))

    def test_hidden_consecutive_near_n(self):
        # 50 consecutive integers, m>=50 gives 0 collisions
        nums = list(range(1, 51))
        self.assertEqual(optimal_hash_size(nums, 49, 53), (50, 0))

if __name__ == '__main__':
    unittest.main()
